import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Line, Doughnut } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale, LinearScale, PointElement, LineElement,
  ArcElement, Tooltip, Legend, Filler
} from 'chart.js';
import { marketAPI, clientsAPI, alertsAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, ArcElement, Tooltip, Legend, Filler);

const StatCard = ({ label, value, sub, trend, color = 'primary' }) => (
  <div className="bg-surface-800 border border-surface-600 rounded-xl p-5">
    <p className="text-xs text-slate-500 uppercase tracking-wider mb-1">{label}</p>
    <p className={`text-2xl font-display font-bold text-${color === 'primary' ? 'primary-400' : color}-400 mb-1`}>{value}</p>
    {sub && <p className={`text-xs ${trend === 'up' ? 'text-green-400' : trend === 'down' ? 'text-red-400' : 'text-slate-500'}`}>{sub}</p>}
  </div>
);

const IndexCard = ({ index }) => {
  const up = index.changePercent >= 0;
  return (
    <div className="bg-surface-700 rounded-lg p-3 border border-surface-600">
      <div className="flex justify-between items-start">
        <div>
          <p className="text-xs text-slate-500 mb-1">{index.name}</p>
          <p className="text-base font-display font-bold text-slate-100">
            {index.value?.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
          </p>
        </div>
        <span className={`text-xs font-medium px-2 py-0.5 rounded-full ${up ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}>
          {up ? '▲' : '▼'} {Math.abs(index.changePercent).toFixed(2)}%
        </span>
      </div>
    </div>
  );
};

const DashboardPage = () => {
  const { advisor } = useAuth();
  const [market, setMarket] = useState(null);
  const [clients, setClients] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [mkt, cli, alts] = await Promise.all([
          marketAPI.getOverview(),
          clientsAPI.getAll({ limit: 5 }),
          alertsAPI.getAll({ limit: 5 })
        ]);
        setMarket(mkt.data);
        setClients(cli.data.clients || []);
        setAlerts(alts.data.alerts || []);
      } catch (e) {
        toast.error('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };
    fetchAll();
    const interval = setInterval(() => {
      marketAPI.getOverview().then(r => setMarket(r.data)).catch(() => {});
    }, 30000); // Refresh market every 30s
    return () => clearInterval(interval);
  }, []);

  // Mock P&L chart
  const chartData = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'],
    datasets: [{
      label: 'Portfolio Value (₹Cr)',
      data: [4.2, 4.5, 4.3, 4.8, 5.1, 4.9, 5.4, 5.8, 5.6, 6.1, 6.4, 6.8],
      borderColor: '#22c55e',
      backgroundColor: 'rgba(34,197,94,0.1)',
      fill: true,
      tension: 0.4,
      pointRadius: 3,
      pointBackgroundColor: '#22c55e'
    }]
  };

  const riskDist = {
    labels: ['Low Risk', 'Medium Risk', 'High Risk'],
    datasets: [{
      data: [30, 45, 25],
      backgroundColor: ['#3b82f6', '#f59e0b', '#ef4444'],
      borderWidth: 0
    }]
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { display: false } },
    scales: {
      x: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b', font: { size: 10 } } },
      y: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b', font: { size: 10 }, callback: v => `₹${v}Cr` } }
    }
  };

  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';

  return (
    <div className="p-6 space-y-6 font-body animate-fade-in">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-display font-bold text-white">
            {greeting}, {advisor?.name?.split(' ')[0]}
          </h1>
          <p className="text-slate-500 text-sm">Here's what's happening in your portfolio today</p>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse" />
          <span className="text-xs text-slate-500">Live</span>
          <Link
            to="/chat"
            className="ml-3 bg-primary-500 hover:bg-primary-600 text-white text-sm font-medium px-4 py-2 rounded-lg transition-colors"
          >
            ✦ Ask AI
          </Link>
        </div>
      </div>

      {/* Stats row */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Total Clients" value={clients.length || '—'} sub="Active portfolios" />
        <StatCard label="AUM" value="₹6.8 Cr" sub="▲ 14.2% YTD" trend="up" />
        <StatCard label="Alerts" value={alerts.filter(a => !a.isRead).length || 0} sub="Unread alerts" color="amber" />
        <StatCard label="Avg Risk Score" value="62/100" sub="Medium risk" color="blue" />
      </div>

      {/* Market indices */}
      <div className="bg-surface-800 border border-surface-600 rounded-xl p-5">
        <div className="flex items-center justify-between mb-4">
          <h2 className="font-display font-bold text-white text-sm">Market Overview</h2>
          <span className="text-xs text-slate-500">
            {market?.timestamp ? new Date(market.timestamp).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' }) : '—'}
          </span>
        </div>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {(market?.indices || []).map(idx => (
            <IndexCard key={idx.name} index={idx} />
          ))}
        </div>
      </div>

      {/* Charts + recent activity */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* AUM trend */}
        <div className="lg:col-span-2 bg-surface-800 border border-surface-600 rounded-xl p-5">
          <h2 className="font-display font-bold text-white text-sm mb-4">AUM Trend — 2024</h2>
          <div style={{ height: 200 }}>
            <Line data={chartData} options={chartOptions} />
          </div>
        </div>

        {/* Risk distribution */}
        <div className="bg-surface-800 border border-surface-600 rounded-xl p-5">
          <h2 className="font-display font-bold text-white text-sm mb-4">Client Risk Profile</h2>
          <div style={{ height: 150 }} className="flex items-center justify-center">
            <Doughnut
              data={riskDist}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                cutout: '65%',
                plugins: { legend: { position: 'bottom', labels: { color: '#64748b', font: { size: 10 }, padding: 10 } } }
              }}
            />
          </div>
        </div>
      </div>

      {/* Alerts + gainers/losers */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Recent alerts */}
        <div className="bg-surface-800 border border-surface-600 rounded-xl p-5">
          <div className="flex justify-between items-center mb-4">
            <h2 className="font-display font-bold text-white text-sm">Recent Alerts</h2>
            <Link to="/alerts" className="text-primary-400 hover:text-primary-300 text-xs">View all</Link>
          </div>
          <div className="space-y-2">
            {alerts.length === 0 ? (
              <p className="text-slate-500 text-sm text-center py-4">No alerts — all portfolios stable</p>
            ) : alerts.slice(0, 4).map(alert => (
              <div key={alert._id} className={`flex items-start gap-3 p-3 rounded-lg ${!alert.isRead ? 'bg-surface-700' : ''}`}>
                <span className={`mt-0.5 text-xs ${alert.severity === 'critical' ? 'text-red-400' : alert.severity === 'high' ? 'text-orange-400' : 'text-yellow-400'}`}>⚑</span>
                <div className="flex-1 min-w-0">
                  <p className="text-xs text-slate-300 truncate">{alert.title}</p>
                  <p className="text-xs text-slate-500 truncate">{alert.message?.slice(0, 60)}...</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Top movers */}
        <div className="bg-surface-800 border border-surface-600 rounded-xl p-5">
          <h2 className="font-display font-bold text-white text-sm mb-4">Market Movers</h2>
          <div className="space-y-2">
            <p className="text-xs text-slate-500 uppercase tracking-wider">Top Gainers</p>
            {(market?.topGainers || []).map(s => (
              <div key={s.symbol} className="flex justify-between items-center py-1">
                <span className="text-xs font-mono text-slate-300">{s.symbol}</span>
                <span className="text-xs text-green-400 font-medium">▲ {s.changePercent}%</span>
              </div>
            ))}
            <div className="border-t border-surface-600 my-2" />
            <p className="text-xs text-slate-500 uppercase tracking-wider">Top Losers</p>
            {(market?.topLosers || []).map(s => (
              <div key={s.symbol} className="flex justify-between items-center py-1">
                <span className="text-xs font-mono text-slate-300">{s.symbol}</span>
                <span className="text-xs text-red-400 font-medium">▼ {Math.abs(s.changePercent)}%</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent clients */}
      <div className="bg-surface-800 border border-surface-600 rounded-xl p-5">
        <div className="flex justify-between items-center mb-4">
          <h2 className="font-display font-bold text-white text-sm">Recent Clients</h2>
          <Link to="/clients" className="text-primary-400 hover:text-primary-300 text-xs">Manage all</Link>
        </div>
        {clients.length === 0 ? (
          <div className="text-center py-8">
            <p className="text-slate-500 text-sm mb-3">No clients yet</p>
            <Link to="/clients" className="bg-primary-500 text-white text-sm px-4 py-2 rounded-lg hover:bg-primary-600 transition-colors">
              Add your first client
            </Link>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs text-slate-500 uppercase tracking-wider">
                  <th className="pb-3">Client</th>
                  <th className="pb-3">Goal</th>
                  <th className="pb-3">Risk</th>
                  <th className="pb-3 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-surface-600">
                {clients.map(client => (
                  <tr key={client._id}>
                    <td className="py-3">
                      <div className="flex items-center gap-3">
                        <div className="w-7 h-7 rounded-full bg-primary-600/30 text-primary-400 text-xs flex items-center justify-center font-medium">
                          {client.initials}
                        </div>
                        <div>
                          <p className="text-slate-200 font-medium">{client.name}</p>
                          <p className="text-slate-500 text-xs">{client.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="py-3">
                      <span className="text-xs text-slate-400">{client.investmentGoal?.replace(/_/g, ' ')}</span>
                    </td>
                    <td className="py-3">
                      <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                        client.riskTolerance === 'high' ? 'bg-red-500/20 text-red-400' :
                        client.riskTolerance === 'medium' ? 'bg-yellow-500/20 text-yellow-400' :
                        'bg-blue-500/20 text-blue-400'
                      }`}>
                        {client.riskTolerance}
                      </span>
                    </td>
                    <td className="py-3 text-right">
                      <Link
                        to={`/clients/${client._id}`}
                        className="text-xs text-primary-400 hover:text-primary-300 transition-colors"
                      >
                        View →
                      </Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default DashboardPage;
